+package java.lang;
+
+/**
+ * An implementation of complex numbers using "textbook" algorithms
+ * for the arithmetic operations and using {@code double} values for
+ * the {@linkplain real() real} and {@linkplain #imag() imaginary}
+ * components.
+ *
+ * <p>For explanatory purposes, in the discussions below of the semantics
+ * of arithmetic methods, two complex numbers
+ * <br>(<i>a</i> + <i>i</i>&middot;<i>b</i>) and (<i>c</i> + <i>i</i>&middot;<i>d</i>)
+ * <br>will be used for notational convenience in specifying the
+ * calculations used to compute the real and imaginary components of the result.
+ *
+ * @apiNote
+ * TODO: For a production-level complex number class, discussion of (real,
+ * imaginary) model, polar coordinates and {@linkplain #proj
+ * projection method}, infinities (complex plane vs Riemann sphere),
+ * branch cuts, component-wise vs norm-wise error, specific algorithms
+ * used subject to change, etc.
+ *
+ * This class is intended only for prototyping and
+ * <em>not</em> intended for production use.
+ *
+ * @see ComplexPolarTextbook
+ */
+// @Deprecated(forRemoval=true)
+// @SuppressWarnings("removal") // Usages from ComplexPolarTextbook
+@jdk.internal.ValueBased
+public final /* value */ class ComplexTextbook  {
+    // This type should be Numerical, but *not* Orderable since
+    // complex numbers are not an ordered field.
+
+    /**
+     * Witness for the {@code Numerical} interface.
+     */
+    public static final __witness Numerical<ComplexTextbook> NUM =
+        new Numerical<ComplexTextbook>() {
+
+        public ComplexTextbook add(ComplexTextbook addend,
+                                   ComplexTextbook augend) {
+            return ComplexTextbook.add(addend, augend);
+        }
+
+        public ComplexTextbook subtract(ComplexTextbook minuend,
+                                        ComplexTextbook subtrahend) {
+            return ComplexTextbook.subtract(minuend, subtrahend);
+        }
+
+        public ComplexTextbook multiply(ComplexTextbook multiplier,
+                                        ComplexTextbook multiplicand) {
+            return ComplexTextbook.multiply(multiplier, multiplicand);
+        }
+
+        public ComplexTextbook divide(ComplexTextbook dividend,
+                                      ComplexTextbook divisor) {
+            return ComplexTextbook.divide(dividend, divisor);
+        }
+
+        public ComplexTextbook remainder(ComplexTextbook dividend,
+                                         ComplexTextbook divisor) {
+            return ComplexTextbook.remainder( dividend,  divisor);
+        }
+
+        public ComplexTextbook plus(ComplexTextbook operand) {
+            return ComplexTextbook.plus(operand);
+        }
+
+        public ComplexTextbook negate(ComplexTextbook operand) {
+            return ComplexTextbook.negate( operand);
+        }
+    };
+
+    /**
+     * The real component of the complex number.
+     */
+    private final double  real;
+
+    /**
+     * The imaginary component of the complex number.
+     * (Note that a more than textbook implementation may use a
+     * separate imaginary type.)
+     */
+    private final double  imag;
+
+    /**
+     * Constructs a complex number.
+     */
+    private ComplexTextbook(double real, double imag) {
+        this.real = real;
+        this.imag = imag;
+    }
+
+    /**
+     * A complex number with the value of zero, both real and
+     * imaginary components of {@code +0.0}.
+     *
+     * @see #isZero(ComplexTextbook)
+     */
+    public static final ComplexTextbook ZERO = valueOf(0.0, 0.0);
+
+    /**
+     * A complex number with a real component of {@code 1.0} and a {@code 0.0}
+     * imaginary component.
+     */
+    public static final ComplexTextbook ONE = valueOf(1.0, 0.0);
+
+    /**
+     * A complex number with a real component of positive infinity and
+     * a {@code 0.0} imaginary component.
+     *
+     * @see #isInfinite(ComplexTextbook)
+     * @see #proj(ComplexTextbook)
+     */
+    public static final ComplexTextbook INFINITY = valueOf(Double.POSITIVE_INFINITY, 0.0);
+
+    /**
+     * A complex number with NaN real component and imaginary
+     * component.
+     *
+     * @see #isNaN(ComplexTextbook)
+     */
+    public static final ComplexTextbook NaN = valueOf(Double.NaN, Double.NaN);
+
+    /**
+     * {@return the real component of this complex number}
+     */
+    public double real() { // better as a static method?
+        return real;
+    }
+
+    /**
+     * {@return the imaginary component of this complex number}
+     */
+    public double imag() { // better as a static method?
+        return imag;
+    }
+
+    /**
+     * {@return a complex number with real and imaginary components
+     * equivalent to the real and imaginary arguments, respectively}
+     *
+     * @param real the real component
+     * @param imag the imaginary component
+     */
+    public static ComplexTextbook valueOf(double real, double imag) {
+        return new ComplexTextbook(real, imag);
+    }
+
+    /**
+     * {@return a complex number with the real component equivalent to the
+     * argument and a {@code +0.0} imaginary component}
+     *
+     * @param real the real component
+     */
+    public static ComplexTextbook valueOf(double real) {
+        return new ComplexTextbook(real, 0.0);
+    }
+
+    /**
+     * {@return a complex number using real and imaginary components from a complex
+     * number using polar coordinates}
+     *
+     * @param cPolar a complex number using polar coordinates
+     */
+    public static ComplexTextbook valueOf(ComplexPolarTextbook cPolar) {
+        double r = cPolar.r();
+        double theta = cPolar.theta();
+        return valueOf(r * StrictMath.cos(theta), r * StrictMath.sin(theta));
+    }
+
+    /**
+     * {@return lorem ipsum}
+     *
+     * @param s the string to be parsed
+     *
+     * @see Double#parseDouble(String)
+     */
+    public static ComplexTextbook valueOf(String s) {
+        throw new UnsupportedOperationException("work in progress");
+    }
+
+    /**
+     * {@return lorem ipsum}
+     *
+     * @apiNote
+     * To convert <em>to</em> polar form, use {@code r = ComplexTextbook.abs(c)} and
+     * {@code theta = Math.atan2(c.imag(), c.real())}.
+     *
+     * @param r the modulus, {@linkplain abs absolute value}, of the
+     * complex number in polar form
+     * @param theta the phase angle of the complex number in polar form
+     *
+     * @see Math#atan2(double, double)
+     */
+    public static ComplexTextbook valueOfPolar(double r, double theta) {
+        return valueOf(r*Math.cos(theta),
+                       r*Math.sin(theta));
+    }
+
+    /**
+     * {@return a string representing the complex number}
+     */
+    @Override
+    public String toString() {
+        return "(" + real + " + " + "i*" + imag  + ")";
+    }
+
+    /**
+     * {@return a string representing the argument}
+     *
+     * @param c the complex number to be represented
+     */
+    public static String toString(ComplexTextbook c) {
+        return c.toString();
+    }
+
+    /**
+     * Compares this complex number with the specified {@code Object}
+     * for equality.
+     *
+     * This method considers two complex numbers equal
+     * if and only if they are equal in both their real and imaginary
+     * components.
+     *
+     * @return {@code true} if and only if the specified {@code Object} is a
+     *         complex number whose real  and imaginary components are equal to this
+     *         complex number's.
+     * @param obj the object to compare this complex number to
+     */
+    @Override
+    public boolean equals(Object obj) {
+        // All four signed complex zero values considered equal to
+        // each other.
+        return obj instanceof ComplexTextbook that &&
+            this.real == that.real &&
+            this.imag == that.imag;
+    }
+
+    /**
+     * {@return a hash code consistent with {@linkplain #equals(Object) equals}}
+     */
+    @Override
+    public int hashCode(){
+        // Add 0.0 to be consistent with current equals impl.
+        return Double.hashCode(real + 0.0) ^ Double.hashCode(imag + 0.0);
+    }
+
+    /**
+     * {@return {@code true} if the two complex arguments are
+     * representationally equivalent and {@code false} otherwise}
+     *
+     * @apiNote
+     * Relate to {@linkplain Double##repEquivalence equivalence
+     * discussion} in {@code double}...
+     *
+     * @param c1 the first complex number
+     * @param c2 the second complex number
+     */
+    public static boolean equivalent(ComplexTextbook c1, ComplexTextbook c2) {
+        return Double.compare(c1.real, c2.real) == 0 &&
+               Double.compare(c1.imag, c2.imag) == 0;
+    }
+
+    // Arithmetic operators
+
+    /**
+     * Addition operation, binary "{@code +}".
+     *
+     * @implSpec
+     * The computed sum is equivalent to
+     * (<i>a</i>&nbsp;+&nbsp;<i>c</i>)&nbsp;+&nbsp;<i>i</i>&middot;(<i>b</i>&nbsp;+&nbsp;<i>d</i>).
+     *
+     * @param addend the first operand
+     * @param augend the second operand
+     * @return the sum of the operands
+     */
+    public static ComplexTextbook add(ComplexTextbook addend,
+                                      ComplexTextbook augend) {
+        double a = addend.real;
+        double b = addend.imag;
+        double c = augend.real;
+        double d = augend.imag;
+
+        return valueOf(a + c, b + d);
+    }
+
+    /**
+     * Subtraction operation, binary "{@code -}".
+     *
+     * @implSpec
+     * The computed difference is equivalent to
+     * (<i>a</i>&nbsp;&minus;&nbsp;<i>c</i>)&nbsp;+&nbsp;<i>i</i>&middot;(<i>b</i>&nbsp;&minus;&nbsp;<i>d</i>).
+     *
+     * @param minuend the first operand
+     * @param subtrahend the second operand
+     * @return the difference of the operands
+     */
+    public static ComplexTextbook subtract(ComplexTextbook minuend,
+                                           ComplexTextbook subtrahend) {
+        double a = minuend.real;
+        double b = minuend.imag;
+        double c = subtrahend.real;
+        double d = subtrahend.imag;
+
+        return valueOf(a - c, b - d);
+    }
+
+    /**
+     * Multiplication operation, "{@code *}".
+     *
+     * @apiNote
+     * WARNING: while simple, the calculation technique used by this
+     * method is subject to spurious underflow and overflow as well as
+     * inaccurate component-wise results.
+     *
+     * @implSpec
+     * The computed product is calculated by
+     * (<i>ac</i>&nbsp;&minus;&nbsp;<i>bd</i>)&nbsp;+&nbsp;<i>i</i>&middot;(<i>ad</i>&nbsp;+&nbsp;<i>bc</i>)
+     *
+     * @param multiplier the first operand
+     * @param multiplicand the second operand
+     * @return the product of the operands
+     */
+    public static ComplexTextbook multiply(ComplexTextbook multiplier,
+                                           ComplexTextbook multiplicand) {
+        double a = multiplier.real;
+        double b = multiplier.imag;
+        double c = multiplicand.real;
+        double d = multiplicand.imag;
+
+        return valueOf(a*c - b*d, a*d + b*c);
+    }
+
+    // See discussion of computation of (ab +/- cd) and complex
+    // arithmetic in Muller et al.'s "Handbook of Floating-Point
+    // Arithmetic, Second Edition (HoFPA).
+
+    // Note: neither the silver nor gold variants currently attempt to
+    // handle non-finite values in a graceful way.
+
+    /**
+     * Multiplication operation, "{@code *}".
+     *
+     * @implSpec
+     * Use accurate component-wise algorithm.
+     *
+     * @param multiplier the first operand
+     * @param multiplicand the second operand
+     * @return the product of the operands
+     */
+    public static ComplexTextbook multiplySilver(ComplexTextbook multiplier,
+                                                 ComplexTextbook multiplicand) {
+        double a = multiplier.real;
+        double b = multiplier.imag;
+        double c = multiplicand.real;
+        double d = multiplicand.imag;
+
+        return valueOf(silver_ad_bc(a, d, b, c),
+                       silver_ad_bc(a, -c, b, d));
+    }
+
+    /**
+     * Multiplication operation, "{@code *}".
+     *
+     * @implSpec
+     * Use accurate component-wise algorithm that is also commutative.
+     *
+     * @param multiplier the first operand
+     * @param multiplicand the second operand
+     * @return the product of the operands
+     */
+    public static ComplexTextbook multiplyGold(ComplexTextbook multiplier,
+                                               ComplexTextbook multiplicand) {
+        double a = multiplier.real;
+        double b = multiplier.imag;
+        double c = multiplicand.real;
+        double d = multiplicand.imag;
+
+        return valueOf(gold_ad_bc(a,  d, b, c),
+                       gold_ad_bc(a, -c, b, d));
+    }
+
+    // HoFPA algorithm 11.1, 2u error bound
+    private static double silver_ad_bc(double a, double b, double c, double d) {
+        double w = b*c;
+        double e = Math.fma(b, c, -w); // exact error
+        double f = a*d - w;
+        return f + e;
+    }
+
+    // HoFPA algorithm 11.2, 2u error bound and symmetrical result
+    private static double gold_ad_bc(double a, double b, double c, double d) {
+        double p1 = a * d;
+        double e1 = Math.fma(a, d, -p1); // a*d - p1, exact error
+
+        double p2 = b * c;
+        double e2 = Math.fma(b, c, -p2); // b*c - p2, exact error
+
+        double p = p1 - p2;
+        double e = e1 - e2;
+        return p + e;
+    }
+
+    /**
+     * Division operation, "{@code /}".
+     *
+     * @apiNote
+     * TODO: Bad numerical things can happen warning...
+     *
+     * @implSpec
+     * The computed quotient is calculated by
+     * (<i>ac</i> + <i>bd</i>)/(<i>c</i>&sup2; + <i>d</i>&sup2;) + <i>i</i>*(<i>bc</i> &minus; <i>ad</i>)/(<i>c</i>&sup2; + <i>d</i>&sup2;)
+     *
+     * @param dividend the value to be divided
+     * @param divisor the value being divided by
+     * @return the quotient of the first argument divided by
+     * the second argument
+     */
+    public static ComplexTextbook divide(ComplexTextbook dividend,
+                                         ComplexTextbook divisor) {
+        double a = dividend.real;
+        double b = dividend.imag;
+        double c = divisor.real;
+        double d = divisor.imag;
+
+        double scale = c*c + d*d;
+
+        return valueOf((a*c + b*d)/scale, (b*c - a*d)/scale);
+    }
+
+    /**
+     * Remainder operation, "{@code %}".
+     *
+     * @param dividend the value to be divided to compute the remainder
+     * @param divisor the value being divided by
+     * @return the remainder of the first argument divided by
+     * the second argument
+     */
+    public static ComplexTextbook remainder(ComplexTextbook dividend,
+                                        ComplexTextbook divisor) {
+        throw new UnsupportedOperationException("tbd");
+    }
+
+    // TODO: API decision, is this method needed?
+
+    /**
+     * Unary plus operation, "{@code +}".
+     *
+     * @param operand the operand
+     * @return unary plus of the operand
+     */
+    public static ComplexTextbook plus(ComplexTextbook operand) {
+        return operand;
+    }
+
+    /**
+     * Negation operation, unary "{@code -}".
+     *
+     * @implSpec
+     * The negation is equivalent to
+     * &minus;<i>a</i>&nbsp;+&nbsp;&minus;<i>i</i>&middot;<i>b</i>
+     *
+     * @param c the operand
+     * @return the negation of the operand
+     */
+    public static ComplexTextbook negate(ComplexTextbook c) {
+        return valueOf(-c.real, -c.imag);
+    }
+
+    /**
+     * {@return the conjugate of the complex number}
+     *
+     * @implSpec
+     * The conjugate is equivalent to
+     * <i>a</i>&nbsp;+&nbsp;&minus;<i>i</i>&middot;<i>b</i>
+     */
+    public ComplexTextbook conj() {
+        return valueOf(this.real, -this.imag);
+    }
+
+    /**
+     * {@return the square root of the argument}.
+     *
+     * @implSpec
+     * Describe error bounds of the return value.
+     *
+     * @param c the operand
+     */
+    public static ComplexTextbook sqrt(ComplexTextbook c) {
+        // See discussions in HoFPA section 11.7.
+        if (isZero(c)) {
+            return ZERO; // TODO: Look up sign of zero conventions
+        }
+
+        // TODO: NaN and infinity handling
+        double a = c.real;
+        double b = c.imag;
+
+        double rho = abs(c);
+        double v = rho + a;
+        double x = Math.sqrt(v * 0.5);
+        double y = b / (2*x);
+        return valueOf(x, y);
+    }
+
+    // Utility methods
+
+    /**
+     * {@return the absolute value of the argument}
+     *
+     * @implSpec
+     * use hypot
+     * @param c a complex number
+     * @see Math#abs(double)
+     */
+    public static double abs(ComplexTextbook c) {
+        double a = c.real;
+        double b = c.imag;
+        return StrictMath.hypot(a, b);
+    }
+
+    /**
+     * {@return the canonical infinity if the argument is {@linkplain
+     * #isInfinite(ComplexTextbook) infinite}; return the argument otherwise}
+     *
+     * @param c a complex number
+     */
+    public static ComplexTextbook proj(ComplexTextbook c) {
+        return isInfinite(c) ? INFINITY : c;
+    }
+
+    /**
+     * {@return {@code true} if both the real and imaginary components
+     * are zero; {@code false} otherwise}
+     *
+     * @param c a complex number
+     */
+    public static boolean isZero(ComplexTextbook c) {
+        return c.real == 0.0 && c.imag == 0.0;
+    }
+
+    /**
+     * {@return {@code true} if either the real or imaginary component
+     * is NaN; {@code false} otherwise}
+     *
+     * @param c a complex number
+     */
+    public static boolean isNaN(ComplexTextbook c) {
+        return Double.isNaN(c.real) || Double.isNaN(c.imag);
+    }
+
+    /**
+     * {@return {@code true} if either the real or imaginary component
+     * is infinite; {@code false} otherwise}
+     *
+     * @param c a complex number
+     */
+    public static boolean isInfinite(ComplexTextbook c) {
+        return Double.isInfinite(c.real) || Double.isInfinite(c.imag);
+    }
+
+    /**
+     * {@return {@code true} if both the real and imaginary components
+     * are finite; {@code false} otherwise}
+     *
+     * @param c a complex number
+     */
+    public static boolean isFinite(ComplexTextbook c) {
+        return Double.isFinite(c.real) && Double.isFinite(c.imag);
+    }
+}

@@ -2035,0 +2035,585 @@
+
+    /**
+     * Exact arithmetic over 32-bit two's complement
+     * integers. Operations that would overflow instead throw {@link
+     * ArithmeticException}.
+     *
+     * @since Valhalla
+     */
+    @jdk.internal.MigratedValueClass
+    @jdk.internal.ValueBased
+    public final static /* value */ class ExactInt  {
+        // NOTE: set of superinterfaces may be expanded in the future.
+
+        private static final Integral<ExactInt> INT = new Integral<ExactInt>() {
+            public ExactInt add(ExactInt addend, ExactInt augend) {
+                return ExactInt.add(addend, augend);
+            }
+
+            @Override
+            public ExactInt subtract(ExactInt minuend, ExactInt subtrahend) {
+                return ExactInt.subtract(minuend, subtrahend);
+            }
+
+            public ExactInt multiply(ExactInt multiplier, ExactInt multiplicand) {
+                return ExactInt.multiply(multiplier, multiplicand);
+            }
+
+            public ExactInt divide(ExactInt dividend, ExactInt divisor) {
+                return ExactInt.divide(dividend, divisor);
+            }
+
+            public ExactInt remainder(ExactInt dividend, ExactInt divisor) {
+                return ExactInt.remainder(dividend, divisor);
+            }
+
+            public ExactInt negate(ExactInt operand) {
+                return ExactInt.negate(operand);
+            }
+
+            public ExactInt and(ExactInt op1, ExactInt op2) {
+                return ExactInt.add(op1, op2);
+            }
+
+            public ExactInt or(ExactInt op1, ExactInt op2) {
+                return ExactInt.or(op1, op2);
+            }
+
+            public ExactInt xor(ExactInt op1, ExactInt op2) {
+                return ExactInt.xor(op1, op2);
+            }
+
+            public ExactInt complement(ExactInt op1) {
+                return ExactInt.complement(op1);
+            }
+
+            public ExactInt shiftLeft(ExactInt x, int shiftDistance) {
+                return ExactInt.shiftLeft(x, shiftDistance);
+            }
+
+            public ExactInt shiftRight(ExactInt x, int shiftDistance) {
+                return ExactInt.shiftRight(x, shiftDistance);
+            }
+
+            public ExactInt shiftRightUnsigned(ExactInt x, int shiftDistance) {
+                return ExactInt.shiftRightUnsigned(x, shiftDistance);
+            }
+
+            @Override
+            public boolean lessThan(ExactInt op1, ExactInt op2) {
+                return ExactInt.lessThan(op1, op2);
+            }
+
+            @Override
+            public boolean lessThanEqual(ExactInt op1, ExactInt op2) {
+                return ExactInt.lessThanEqual(op1, op2);
+            }
+
+            @Override
+            public boolean greaterThan(ExactInt op1, ExactInt op2) {
+                return ExactInt.greaterThan(op1, op2);
+            }
+
+            @Override
+            public boolean greaterThanEqual(ExactInt op1, ExactInt op2) {
+                return ExactInt.greaterThanEqual(op1, op2);
+            }
+
+            public ExactInt min(ExactInt op1, ExactInt op2) {
+                return ExactInt.min(op1, op2);
+            }
+
+            public ExactInt max(ExactInt op1, ExactInt op2) {
+                return ExactInt.max(op1, op2);
+            }
+        };
+
+        /**
+         * Witness for the {@code Numerical} interface.
+         */
+        public static final __witness Numerical<ExactInt> NUM = INT;
+
+        /**
+         * Witness for the {@code Orderable} interface.
+         */
+        public static final __witness Orderable<ExactInt> ORD = INT;
+
+        /**
+         * A constant holding an {@code ExactInt} 0.
+         */
+        public static final ExactInt ZERO = valueOf(0);
+
+        /**
+         * A constant holding an {@code ExactInt} 1.
+         */
+        public static final ExactInt ONE  = valueOf(1);
+
+        /**
+         * A constant holding the minimum value an {@code ExactInt} can
+         * have, -2<sup>31</sup>.
+         */
+        public static final ExactInt MIN_VALUE = valueOf(Integer.MIN_VALUE);
+
+        /**
+         * A constant holding the maximum value an {@code ExactInt}
+         * can have, 2<sup>31</sup>-1.
+         */
+        public static final ExactInt MAX_VALUE = valueOf(Integer.MAX_VALUE);
+
+
+        /**
+         * The bits of the exact value.
+         */
+        private int value;
+
+        /**
+         * Constructs a new exact int.
+         */
+        private ExactInt(int value) {
+            this.value = value;
+        }
