+                @Override
+                public void success(String string) {
+                    first.success(string);
+                    second.success(string);
+                }
+
+                @Override
+                public void ambiguous() {
+                    first.ambiguous();
+                    second.ambiguous();
+                }
+
+                @Override
+                public void notFound() {
+                    first.notFound();
+                    second.notFound();
+                }
+            };
+        }
+
+        static Result dummy() {
+            return new Result() {
+                @Override
+                public void success(String string) { }
+                @Override
+                public void ambiguous() { }
+                @Override
+                public void notFound() { }
+            };
+        }
